  ('aboriginal-f7485f85-moex-00068', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X1年初的權益總額為$366,500，X1年底的權益總額為$492,500。X1年度相關事項如 下：更正去年漏記之保險費$6,000、淨利$120,000、發行面額$10之普通股2,000股、處分交 通設備利得$4,000、指撥法定盈餘公積$5,000、宣告並發放普通股現金股利$20,000。若甲公司 無其他權益項目，則甲公司於X1年「資本公積-普通股溢價」之變動金額為：', '["$0", "增加$8,000", "增加$12,000", "增加$17,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
