  ('aboriginal-f7485f85-moex-00070', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司 X1 年初成立，一場暴雨讓甲公司倉庫之商品被大水沖走，但會計帳簿尚存。該公司 X1 年度之進貨$50,000，進貨折讓$5,500，進貨運費$3,500，進貨之零售價$100,000，銷貨 $70,000。甲公司採定期盤存制，則該公司採零售價法估計之X1年期末存貨成本為：', '["$14,400", "$15,000", "$22,000", "$68,571"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL)
